const f="Asia/Ho_Chi_Minh";function s(e){if(e==null)return null;if(typeof e!="string")return new Date(e);const t=e.replace(" ","T").trim();return/^\d{4}-\d{2}-\d{2}(T|\s)\d{2}:\d{2}/.test(t)&&!t.endsWith("Z")&&!/[-+]\d{2}:?\d{2}$/.test(t)?new Date(t+"+07:00"):new Date(t)}function u(e){const t=s(e);if(!t||Number.isNaN(t.getTime()))return"";const n=new Date-t,r=Math.floor(n/6e4),i=Math.floor(n/36e5),o=Math.floor(n/864e5);return r<1?"Vừa xong":r<60?`${r} phút trước`:i<24?`${i} giờ trước`:o<7?`${o} ngày trước`:t.toLocaleDateString("vi-VN",{timeZone:f})}function c(e){const t=s(e);return!t||Number.isNaN(t.getTime())?"":t.toLocaleString("vi-VN",{timeZone:f,dateStyle:"short",timeStyle:"short"})}export{c as a,u as f};
